var builder = DistributedApplication.CreateBuilder(args);

// Separate Write and Read stores
var writeDb = builder.AddPostgres("pg-write")
    .AddDatabase("orderswrite");
var readDb = builder.AddPostgres("pg-read")
    .AddDatabase("ordersread");
var rabbitmq = builder.AddRabbitMQ("rabbitmq");
var redis = builder.AddRedis("redis");

// Command API — validates and persists commands
var commandApi = builder.AddProject<Projects.CommandApi>("command-api")
    .WithReference(writeDb)
    .WithReference(rabbitmq)
    .WaitFor(writeDb)
    .WaitFor(rabbitmq);

// Event Projector — builds read models from events
var projector = builder.AddProject<Projects.Projector>("projector")
    .WithReference(rabbitmq)
    .WithReference(readDb)
    .WaitFor(rabbitmq)
    .WaitFor(readDb);

// Query API — serves read-optimized queries
var queryApi = builder.AddProject<Projects.QueryApi>("query-api")
    .WithReference(readDb)
    .WithReference(redis)
    .WaitFor(readDb);

// YARP Gateway routes writes vs reads
var gateway = builder.AddProject<Projects.Gateway>("gateway")
    .WithReference(commandApi)
    .WithReference(queryApi)
    .WaitFor(commandApi)
    .WaitFor(queryApi);

// Frontend
builder.AddNpmApp("frontend", "../frontend")
    .WithReference(gateway)
    .WithHttpEndpoint(env: "PORT")
